import pika
import time

# RabbitMQ connection parameters
rabbitmq_host = 'localhost'
rabbitmq_port = 5672
rabbitmq_queue = 'task_queue'

# Publisher
connection = pika.BlockingConnection(pika.ConnectionParameters(host=rabbitmq_host, port=rabbitmq_port))
channel = connection.channel()
channel.queue_declare(queue=rabbitmq_queue)

while True:
    # Generate task message
    task_message = "Task message"

    # Send task message to RabbitMQ queue
    channel.basic_publish(exchange='', routing_key=rabbitmq_queue, body=task_message.encode())
    print("Task message sent:", task_message)

    time.sleep(1)

# Close RabbitMQ connection
connection.close()

# Consumer
connection = pika.BlockingConnection(pika.ConnectionParameters(host=rabbitmq_host, port=rabbitmq_port))
channel = connection.channel()
channel.queue_declare(queue=rabbitmq_queue)

# Consume task messages from RabbitMQ queue
while True:
    method_frame, header_frame, body = channel.basic_get(queue=rabbitmq_queue)

    if method_frame:
        # Process task message
        task_message = body.decode()
        print("Task message received:", task_message)

        # Acknowledge message consumption
        channel.basic_ack(delivery_tag=method_frame.delivery_tag)
    else:
        time.sleep(1)